// ============================================
// VALIDATION
// ============================================

/**
 * Validate input parameters
 */
export function validateSeoHealthDashboardInput(input: SeoHealthDashboardInput): { valid: boolean; errors: string[] } {
  const errors: string[] = [];

  if (!input.projectId) {
    errors.push('Project is required');
  }

  if (!input.crawlRunId) {
    errors.push('Crawl Run is required');
  }

  return {
    valid: errors.length === 0,
    errors,
  };
}

